export type BranchRelation = '방합' | '삼합' | '육합' | '중립' | '충' | '파' | '해' | '형'
export type Ohang = '土' | '木' | '水' | '火' | '金'
export type DualRelationKey = `${BranchRelation}|${BranchRelation}`
export type SupportKey = `${'B→A' | 'A→B'}|${Ohang}`
export type TransitionKey = 'both' | 'me' | 'target' | 'none'

export interface FortuneCopyEntry {
  summary: string
  detail: string
}

function normalizeFortuneCopyEntry(entry: FortuneCopyEntry): FortuneCopyEntry {
  return {
    summary: entry.summary,
    detail: entry.detail.replace(/\s*\n+\s*/g, ' ').trim(),
  }
}

function normalizeFortuneCopyMap<T extends string>(
  source: Record<T, FortuneCopyEntry>,
): Record<T, FortuneCopyEntry> {
  const normalizedEntries = (Object.keys(source) as T[]).map((key) => [
    key,
    normalizeFortuneCopyEntry(source[key]),
  ])

  return Object.fromEntries(normalizedEntries) as Record<T, FortuneCopyEntry>
}

